import{_ as e,c as a,o as s,a as t}from"./app.a34d0aa4.js";const g=JSON.parse('{"title":"Filter and sort grep matches","description":"","frontmatter":{},"headers":[{"level":2,"title":"First part: grep","slug":"first-part-grep","link":"#first-part-grep","children":[]},{"level":2,"title":"Second part: awk","slug":"second-part-awk","link":"#second-part-awk","children":[{"level":3,"title":"More Info and Alternatives","slug":"more-info-and-alternatives","link":"#more-info-and-alternatives","children":[]}]},{"level":2,"title":"Third part: sort","slug":"third-part-sort","link":"#third-part-sort","children":[]},{"level":2,"title":"Final Result","slug":"final-result","link":"#final-result","children":[]}],"relativePath":"misc/grep-awk-sort.md"}'),o={name:"misc/grep-awk-sort.md"},n=t(`<h1 id="filter-and-sort-grep-matches" tabindex="-1">Filter and sort grep matches <a class="header-anchor" href="#filter-and-sort-grep-matches" aria-hidden="true">#</a></h1><p>Searching for pattern in all folders and files of the current directory and sorting the result from highest to lowest number of occurences.</p><div class="language-sh"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki material-theme-palenight"><code><span class="line"><span style="color:#FFCB6B;">grep</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">-Erc</span><span style="color:#A6ACCD;"> </span><span style="color:#89DDFF;">&#39;</span><span style="color:#C3E88D;">[fF]oobar</span><span style="color:#89DDFF;">&#39;</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">.</span><span style="color:#A6ACCD;"> </span><span style="color:#89DDFF;">|</span><span style="color:#A6ACCD;"> </span><span style="color:#FFCB6B;">awk</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">-v</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">FS=</span><span style="color:#89DDFF;">&quot;</span><span style="color:#C3E88D;">:</span><span style="color:#89DDFF;">&quot;</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">-v</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">OFS=</span><span style="color:#89DDFF;">&quot;</span><span style="color:#C3E88D;">\\t</span><span style="color:#89DDFF;">&quot;</span><span style="color:#A6ACCD;"> </span><span style="color:#89DDFF;">&#39;</span><span style="color:#C3E88D;">$2&gt;0 { print $2, $1 }</span><span style="color:#89DDFF;">&#39;</span><span style="color:#A6ACCD;"> </span><span style="color:#89DDFF;">|</span><span style="color:#A6ACCD;"> </span><span style="color:#FFCB6B;">sort</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">-hr</span></span>
<span class="line"></span></code></pre></div><h2 id="first-part-grep" tabindex="-1">First part: <code>grep</code> <a class="header-anchor" href="#first-part-grep" aria-hidden="true">#</a></h2><p><a href="https://man7.org/linux/man-pages/man1/grep.1.html" target="_blank" rel="noreferrer">https://man7.org/linux/man-pages/man1/grep.1.html</a></p><ul><li><code>E</code> - Use extended regular expressions (ERE) instead of basic ones (BRE)</li><li><code>r</code> - Read all files under each directory, recursively</li><li><code>c</code> - Suppress normal output; instead print a count of matching lines for each input file.</li></ul><p><strong>Example output:</strong></p><blockquote><p>./docs/index.md:3<br> ./docs/misc/unix-time.md:2<br> ./docs/misc/deployment.md:0<br> ./docs/misc/ssh-add-startup.md:0<br> ./docs/misc/editorconfig-naming-convention.md:7<br> ./docs/misc/find-delete-files.md:1</p></blockquote><h2 id="second-part-awk" tabindex="-1">Second part: <code>awk</code> <a class="header-anchor" href="#second-part-awk" aria-hidden="true">#</a></h2><p><a href="https://man7.org/linux/man-pages/man1/awk.1p.html" target="_blank" rel="noreferrer">https://man7.org/linux/man-pages/man1/awk.1p.html</a></p><p><code>awk</code> is going to filter out files with 0 matches and change the structure of the output from <code>&lt;file&gt;:&lt;matches&gt;</code> to <code>&lt;matches&gt;tab&lt;file&gt;</code>.</p><ul><li><code>-v FS=&quot;:&quot;</code> - This is creating a variable called <code>FS</code> and assigning the value <code>:</code> to it.</li><li><code>-v OFS=&quot;\\t&quot;</code> - This is creating a variable called <code>OFS</code> and assigning the value <code>\\t</code> to it.</li><li><code>&#39;$2&gt;0 { print $2, $1 }&#39;</code> - Print every line where the 2nd column <code>$2</code> is greater than 0. First print the 2nd column and then the 1st column.</li></ul><p><strong>Example output:</strong></p><blockquote><p>3 ./docs/index.md<br> 2 ./docs/misc/unix-time.md<br> 7 ./docs/misc/editorconfig-naming-convention.md<br> 1 ./docs/misc/find-delete-files.md</p></blockquote><h3 id="more-info-and-alternatives" tabindex="-1">More Info and Alternatives <a class="header-anchor" href="#more-info-and-alternatives" aria-hidden="true">#</a></h3><blockquote><p>-v var=val<br> --assign var=val<br> Assign the value val to the variable var, before execution of the program begins. Such variable values are available to the <strong>BEGIN</strong> block of an AWK program.</p></blockquote><p>The following <code>awk</code> commands produce the same result.</p><div class="language-sh"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki material-theme-palenight"><code><span class="line"><span style="color:#FFCB6B;">awk</span><span style="color:#A6ACCD;"> </span><span style="color:#89DDFF;">&#39;</span><span style="color:#C3E88D;">BEGIN{FS=&quot;:&quot;; OFS=&quot;\\t&quot;} $2&gt;0 { print $2, $1 }</span><span style="color:#89DDFF;">&#39;</span></span>
<span class="line"><span style="color:#FFCB6B;">awk</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">-F:</span><span style="color:#A6ACCD;"> </span><span style="color:#89DDFF;">&#39;</span><span style="color:#C3E88D;">$2&gt;0 { print $2 &quot;\\t&quot; $1 }</span><span style="color:#89DDFF;">&#39;</span></span>
<span class="line"></span></code></pre></div><h2 id="third-part-sort" tabindex="-1">Third part: <code>sort</code> <a class="header-anchor" href="#third-part-sort" aria-hidden="true">#</a></h2><p><a href="https://man7.org/linux/man-pages/man1/sort.1.html" target="_blank" rel="noreferrer">https://man7.org/linux/man-pages/man1/sort.1.html</a></p><p>Default behavior of <code>sort</code> command is to sort by the first column/field/key whatever you wanna call it. The default field separator is a blank space. The whole command seems to work either way ¯\\_(ツ)_/¯</p><ul><li><code>h</code> - Human readable</li><li><code>r</code> - Default is ascending, this option reverses the order so the output is sorted in descending order.</li></ul><h2 id="final-result" tabindex="-1">Final Result <a class="header-anchor" href="#final-result" aria-hidden="true">#</a></h2><p>So the command <code>grep | awk | sort</code> produces a result that looks something like this:</p><blockquote><p>7 ./docs/misc/editorconfig-naming-convention.md<br> 3 ./docs/index.md<br> 2 ./docs/misc/unix-time.md<br> 1 ./docs/misc/find-delete-files.md</p></blockquote>`,25),r=[n];function l(c,i,p,d,h,u){return s(),a("div",null,r)}const f=e(o,[["render",l]]);export{g as __pageData,f as default};
